import { useNavigate } from "react-router-dom";
import booksData from "../data/booksData";
import "./styles/LibrarianBooks.css";

function LibrarianBooks() {
  const navigate = useNavigate();

  const genre = localStorage.getItem("genre");
  console.log("GENRE:", genre);
  console.log("AVAILABLE:", Object.keys(booksData));

  const books = genre ? booksData[genre] : null;

  if (!genre || !books) {
    return (
      <div className="books-page">
        <h1 className="books-title">Genre not found</h1>
        <button className="back-btn" onClick={() => navigate(-1)}>
          ← Back
        </button>
      </div>
    );
  }

  return (
    <div className="books-page">
      <h1 className="books-title">Manage {genre} Books</h1>

      <div className="books-grid">
        {books.map((book, i) => (
          <div key={i} className="book-card">
            <img src={book.cover} alt={book.title} />
            <h3>{book.title}</h3>
            <p>{book.author}</p>
          </div>
        ))}
      </div>

      <div className="action-buttons">
        <button className="back-btn" onClick={() => navigate(-1)}>
          ← Back
        </button>
      </div>
    </div>
  );
}

export default LibrarianBooks;
